mapper.select:
WITH filtered_bills AS ( SELECT b.bill_id, b.amount FROM fortune_bill b
b.include = TRUE AND b.bill_type = #{billType} AND b.deleted = 0
AND b.title LIKE CONCAT('%', #{query.title}, '%') AND b.trade_time <= CONCAT(#{query.endDate}, ' 23:59:59')
), total AS (SELECT SUM(amount) AS total_amount FROM filtered_bills) SELECT c.category_name AS name, SUM(fb.amount) AS value, (SUM(fb.amount) / (SELECT total_amount FROM total)) * 100 AS percent FROM filtered_bills fb INNER JOIN fortune_category_relation cr ON fb.bill_id = cr.bill_id INNER JOIN fortune_category c ON cr.category_id = c.category_id CROSS JOIN total t
WHERE cr.category_id IN #{item}
GROUP BY c.category_id

WITH filtered_bills AS ( SELECT b.bill_id, b.amount FROM fortune_bill b
b.include = 1 AND b.bill_type = #{billType} AND b.deleted = 0
AND b.title LIKE '%' || #{query.title} || '%' AND b.trade_time <= #{query.endDate} || ' 23:59:59'
), total AS (SELECT SUM(amount) AS total_amount FROM filtered_bills) SELECT c.category_name AS name, SUM(fb.amount) AS value, (SUM(fb.amount) / (SELECT total_amount FROM total)) * 100 AS percent FROM filtered_bills fb INNER JOIN fortune_category_relation cr ON fb.bill_id = cr.bill_id INNER JOIN fortune_category c ON cr.category_id = c.category_id CROSS JOIN total t
WHERE cr.category_id IN #{item}
GROUP BY c.category_id
